import io
from azure.storage.blob import BlobClient, ContainerClient


def main(request):
    blob = getblob(request)
    return blob.readall()

def getblob(request):
    params = request.params
    containername = "container"
    filename = None

    for key in ["container", "filename"]:
        if (key not in params or len(params[key]) < 1):
            return None

        value = params[key]
        filename = filename + "/" + value

    c = ContainerClient("<storageaccount>", containername)

    print('Listing blobs...')
    bloblist = list(c.list_blobs(include="metadata"))


    for blob in bloblist:
        print("\t Blob path: {}.".format(blob))

    return  c.get_blob_client(container=containername, blob=filename)


